    16→
    17→// Helper to check if an item is a DashboardGroup
    18→function isDashboardGroup(item: unknown): item is DashboardGroup {
    19→  return (
    20→    typeof item === "object" &&
    21→    item !== null &&
    22→    "title" in item &&
    23→    "charts" in item &&
    24→    Array.isArray((item as { charts: unknown }).charts)
    25→  );
    26→}
    27→
    28→// Generate default layouts from dashboard panels
    29→function generateDefaultLayouts(dashboard: Dashboard): ResponsiveLayouts {
    30→  const allPanels: PanelDescriptor[] = [];
    31→  dashboard.charts.forEach((item) => {
    32→    if (isDashboardGroup(item)) {
    33→      allPanels.push(...item.charts);
    34→    } else {
    35→      allPanels.push(item);
    36→    }
    37→  });
    38→
    39→  const lg: LayoutItem[] = [];
    40→  const md: LayoutItem[] = [];
    41→  const sm: LayoutItem[] = [];
    42→
    43→  allPanels.forEach((panel, index) => {
    44→    const gridPos = panel.gridPos ?? { w: 24, h: 6 };
    45→    const constraints = getPanelConstraints(panel.type);
    46→    const key = `panel-${index}`;
    47→
    48→    lg.push({
    49→      i: key,
    50→      x: gridPos.x ?? (index * 6) % 24,
    51→      y: gridPos.y ?? Math.floor((index * 6) / 24) * 4,
    52→      w: gridPos.w,
    53→      h: gridPos.h,
    54→      ...constraints,
    55→    });
    56→
    57→    const mdW = Math.max(constraints.minW, Math.round((gridPos.w / 24) * 6));
    58→    md.push({
    59→      i: key,
    60→      x: (index * 3) % 6,
    61→      y: Math.floor((index * 3) / 6) * 4,
    62→      w: Math.min(mdW, 6),
    63→      h: gridPos.h,
    64→      minW: Math.min(constraints.minW, 6),
    65→      minH: constraints.minH,
    66→      maxW: 6,
    67→      maxH: constraints.maxH,
    68→    });
    69→
    70→    sm.push({
    71→      i: key,
    72→      x: 0,
    73→      y: index * 4,
    74→      w: 1,
    75→      h: gridPos.h,
    76→      minW: 1,
    77→      minH: constraints.minH,
    78→      maxW: 1,
    79→      maxH: constraints.maxH,
    80→      static: true,
    81→    });
    82→  });
    83→
    84→  return { lg, md, sm };
    85→}
    86→
    87→export interface DashboardPageRef {
    88→  setSelectedTimeSpan: (timeSpan: TimeSpan) => void;
    89→  setFilter: (filterName: string, value: string) => void;
    90→}
    91→
    92→interface DashboardPageProps {
    93→  panels: Dashboard;
    94→  filterSpecs?: FilterSpec[];
    95→  showInputFilter?: boolean;
    96→  headerActions?: React.ReactNode;
    97→  timezone?: string;
    98→  showTimeSpanSelector?: boolean;
    99→  showRefresh?: boolean;
   100→  showAutoRefresh?: boolean;
   101→  chartSelectionFilterName?: string;
   102→  /**
   103→   * Unique identifier for this dashboard (used for layout persistence).
   104→   * If not provided, layout won't be persisted.
   105→   */
   106→  dashboardId?: string;
   107→  /**
   108→   * Children to render below the dashboard panels.
   109→   * Children can use the useDashboardRefresh hook to register
