   123→// Inner component to access layout context
   124→interface DashboardFilterWithResetProps {
   125→  filterRef: React.RefObject<DashboardFilterComponent | null>;
   126→  filterSpecs: FilterSpec[];
   127→  onFilterChange?: (filter: SelectedFilter) => void;
   128→  onTimeSpanChange?: (timeSpan: TimeSpan) => void;
   129→  onLoadSourceData?: (query: SQLQuery) => Promise<string[]>;
   130→  timezone?: string;
   131→  showTimeSpanSelector?: boolean;
   132→  showRefresh?: boolean;
   133→  showAutoRefresh?: boolean;
   134→  headerActions?: React.ReactNode;
   135→}
   136→
   137→function DashboardFilterWithReset({
   138→  filterRef,
   139→  filterSpecs,
   140→  onFilterChange,
   141→  onTimeSpanChange,
   142→  onLoadSourceData,
   143→  timezone,
   144→  showTimeSpanSelector,
   145→  showRefresh,
   146→  showAutoRefresh,
   147→  headerActions,
   148→}: DashboardFilterWithResetProps) {
   149→  const { resetLayout } = useDashboardLayout();
   150→
   151→  return (
   152→    <DashboardFilterComponent
   153→      ref={filterRef}
   154→      filterSpecs={filterSpecs}
   155→      onFilterChange={onFilterChange}
   156→      onTimeSpanChange={onTimeSpanChange}
   157→      onLoadSourceData={onLoadSourceData}
   158→      timezone={timezone}
   159→      showTimeSpanSelector={showTimeSpanSelector}
   160→      showRefresh={showRefresh}
   161→      showAutoRefresh={showAutoRefresh}
   162→      onResetLayout={resetLayout}
   163→    >
   164→      {headerActions}
   165→    </DashboardFilterComponent>
   166→  );
