   260→      const timer = setTimeout(() => {
   261→        if (filterRef.current) {
   262→          const timeSpan = filterRef.current.getSelectedTimeSpan();
   263→          const filter = filterRef.current.getSelectedFilter();
   264→          refreshPanels(timeSpan, filter);
   265→        }
   266→      }, 0);
   267→
   268→      return () => clearTimeout(timer);
   269→    }, [refreshPanels]);
   270→
   271→    const handleSelectionFilterChange = useCallback(
   272→      (filter: SelectedFilter) => {
   273→        const timeSpan = filterRef.current?.getSelectedTimeSpan();
   274→        if (!timeSpan) {
   275→          return;
   276→        }
   277→        refreshPanels(timeSpan, filter);
   278→      },
   279→      [refreshPanels]
   280→    );
   281→
   282→    const handleTimeSpanChange = useCallback(
   283→      (timeSpan: TimeSpan) => {
   284→        const filter = filterRef.current?.getSelectedFilter();
   285→        refreshPanels(timeSpan, filter);
   286→      },
   287→      [refreshPanels]
   288→    );
   289→
   290→    const handleInputFilterKeyDown = useCallback(
   291→      (event: React.KeyboardEvent<HTMLInputElement>) => {
   292→        if (event.key === "Enter") {
   293→          const inputFilterValue = inputFilterRef.current?.value || "";
   294→          const timeSpan = filterRef.current?.getSelectedTimeSpan();
   295→          const filter = filterRef.current?.getSelectedFilter();
   296→          if (timeSpan) {
   297→            refreshPanels(timeSpan, filter, inputFilterValue);
   298→          }
   299→        }
   300→      },
   301→      [refreshPanels]
   302→    );
   303→
   304→    const handleChartSelection = useCallback(
   305→      (timeSpan: TimeSpan, selection: { name: string; series: string; value: number }) => {
   306→        filterRef.current?.setSelectedTimeSpan(timeSpan);
   307→        if (chartSelectionFilterName && selection.series) {
   308→          filterRef.current?.setFilter(chartSelectionFilterName, selection.series);
   309→        }
   310→      },
   311→      [chartSelectionFilterName]
   312→    );
   313→
   314→    const hasFilters = filterSpecs && filterSpecs.length > 0;
   315→
   316→    const dashboardContent = (
   317→      <div className="flex flex-col h-full w-full overflow-hidden p-2 gap-2">
   318→        {dashboardId ? (
   319→          // With layout provider - use DashboardFilterWithReset for reset button
   320→          <DashboardFilterWithReset
   321→            filterRef={filterRef}
   322→            filterSpecs={hasFilters ? filterSpecs : []}
   323→            onFilterChange={hasFilters ? handleSelectionFilterChange : undefined}
   324→            onTimeSpanChange={handleTimeSpanChange}
   325→            onLoadSourceData={hasFilters ? defaultLoadFilterData : undefined}
   326→            timezone={timezone}
   327→            showTimeSpanSelector={showTimeSpanSelector}
   328→            showRefresh={showRefresh}
   329→            showAutoRefresh={showAutoRefresh}
   330→            headerActions={headerActions}
   331→          />
   332→        ) : (
   333→          // Without layout provider - regular filter without reset
   334→          <DashboardFilterComponent
   335→            ref={filterRef}
   336→            filterSpecs={hasFilters ? filterSpecs : []}
   337→            onFilterChange={hasFilters ? handleSelectionFilterChange : undefined}
   338→            onTimeSpanChange={handleTimeSpanChange}
   339→            onLoadSourceData={hasFilters ? defaultLoadFilterData : undefined}
   340→            timezone={timezone}
   341→            showTimeSpanSelector={showTimeSpanSelector}
   342→            showRefresh={showRefresh}
   343→            showAutoRefresh={showAutoRefresh}
   344→          >
   345→            {headerActions}
   346→          </DashboardFilterComponent>
   347→        )}
   348→
   349→        {showInputFilter && (
   350→          <div className="relative">
   351→            <Input
   352→              ref={inputFilterRef}
   353→              className="rounded-l rounded-r pl-2 h-8"
   354→              placeholder="Input filter expression, press ENTER to apply"
   355→              onKeyDown={handleInputFilterKeyDown}
   356→            />
   357→          </div>
   358→        )}
   359→
   360→        <div className="flex-1 min-h-0 overflow-hidden">
   361→          <DashboardPanelContainer
   362→            ref={panelsRef}
   363→            dashboard={panels}
   364→            dashboardId={dashboardId}
   365→            initialLoading={false}
   366→            onChartSelection={chartSelectionFilterName ? handleChartSelection : undefined}
   367→            showSectionEditControls={showSectionEditControls}
   368→            onSectionRename={onSectionRename}
   369→            onSectionDelete={onSectionDelete}
   370→            onSectionCollapseChange={onSectionCollapseChange}
   371→          >
   372→            {children}
   373→          </DashboardPanelContainer>
   374→        </div>
   375→      </div>
   376→    );
   377→
   378→    // Wrap with layout provider if dashboardId is provided
   379→    if (dashboardId) {
   380→      return (
   381→        <DashboardLayoutProvider dashboardId={dashboardId} defaultLayouts={defaultLayouts}>
   382→          {dashboardContent}
   383→        </DashboardLayoutProvider>
   384→      );
   385→    }
   386→
   387→    return dashboardContent;
   388→  }
   389→);
   390→
   391→export default DashboardPage;
