     1→"use client";
     2→
     3→import React, { createContext, useCallback, useContext, useEffect, useMemo, useRef, useState } from 'react';
     4→import type { Layout, ResponsiveLayouts } from 'react-grid-layout';
     5→import { loadDashboardLayout, saveDashboardLayout, clearDashboardLayout, clearAllSectionLayouts } from './dashboard-layout-storage';
     6→
     7→interface DashboardLayoutContextValue {
     8→  layouts: ResponsiveLayouts;
     9→  onLayoutChange: (currentLayout: Layout, allLayouts: ResponsiveLayouts) => void;
    10→  resetLayout: () => void;
    11→  isEditing: boolean;
    12→}
    13→
    14→const DashboardLayoutContext = createContext<DashboardLayoutContextValue | null>(null);
    15→
    16→interface DashboardLayoutProviderProps {
    17→  dashboardId: string;
    18→  defaultLayouts: ResponsiveLayouts;
    19→  children: React.ReactNode;
    20→}
    21→
    22→export function DashboardLayoutProvider({
    23→  dashboardId,
    24→  defaultLayouts,
    25→  children,
    26→}: DashboardLayoutProviderProps) {
    27→  const [layouts, setLayouts] = useState<ResponsiveLayouts>(() => {
    28→    const saved = loadDashboardLayout(dashboardId);
    29→    return saved ?? defaultLayouts;
    30→  });
    31→
    32→  // Debounce save to localStorage
    33→  const saveTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    34→
    35→  const onLayoutChange = useCallback(
    36→    (currentLayout: Layout, allLayouts: ResponsiveLayouts) => {
    37→      setLayouts(allLayouts);
    38→
    39→      // Debounced save
    40→      if (saveTimeoutRef.current) {
    41→        clearTimeout(saveTimeoutRef.current);
    42→      }
    43→      saveTimeoutRef.current = setTimeout(() => {
    44→        saveDashboardLayout(dashboardId, allLayouts);
    45→      }, 500);
    46→    },
    47→    [dashboardId]
    48→  );
    49→
    50→  const resetLayout = useCallback(() => {
    51→    // Clear both legacy single-dashboard layout and all section layouts
    52→    clearDashboardLayout(dashboardId);
    53→    clearAllSectionLayouts(dashboardId);
    54→    setLayouts(defaultLayouts);
    55→  }, [dashboardId, defaultLayouts]);
    56→
    57→  // Cleanup timeout on unmount
    58→  useEffect(() => {
    59→    return () => {
    60→      if (saveTimeoutRef.current) {
    61→        clearTimeout(saveTimeoutRef.current);
    62→      }
    63→    };
    64→  }, []);
    65→
    66→  const value = useMemo<DashboardLayoutContextValue>(
    67→    () => ({
    68→      layouts,
    69→      onLayoutChange,
    70→      resetLayout,
    71→      isEditing: true, // Always editable for now
    72→    }),
    73→    [layouts, onLayoutChange, resetLayout]
    74→  );
    75→
    76→  return (
    77→    <DashboardLayoutContext.Provider value={value}>
    78→      {children}
    79→    </DashboardLayoutContext.Provider>
    80→  );
    81→}
    82→
    83→export function useDashboardLayout(): DashboardLayoutContextValue {
    84→  const ctx = useContext(DashboardLayoutContext);
    85→  if (!ctx) {
    86→    throw new Error('useDashboardLayout must be used within DashboardLayoutProvider');
    87→  }
    88→  return ctx;
    89→}
    90→
    91→export function useDashboardLayoutOptional(): DashboardLayoutContextValue | null {
    92→  return useContext(DashboardLayoutContext);
    93→}
