   111→// Helper function to check if an item is a DashboardGroup
   112→function isDashboardGroup(item: unknown): item is DashboardGroup {
   113→  return (
   114→    typeof item === "object" &&
   115→    item !== null &&
   116→    "title" in item &&
   117→    "charts" in item &&
   118→    Array.isArray((item as { charts: unknown }).charts)
   119→  );
   120→}
   121→
   122→// Helper function to flatten all charts (including charts in groups)
   123→function getAllCharts(charts: (PanelDescriptor | DashboardGroup)[]): PanelDescriptor[] {
   124→  const allCharts: PanelDescriptor[] = [];
   125→  charts.forEach((item) => {
   126→    if (isDashboardGroup(item)) {
   127→      allCharts.push(...item.charts);
   128→    } else {
   129→      allCharts.push(item);
   130→    }
   131→  });
   132→  return allCharts;
   133→}
   134→
   135→/** Single source of truth for dashboard grid column counts: mobile | tablet | desktop */
   136→export type DashboardGridColumns = 1 | 6 | 24;
   137→
   138→/** Represents a section with its panels and metadata */
   139→interface SectionInfo {
   140→  group: DashboardGroup | null; // null for ungrouped panels
   141→  sectionIndex: number;
   142→  panels: PanelDescriptor[];
   143→  globalPanelStartIndex: number; // Global index of first panel in this section
   144→}
   145→
   146→const DashboardPanelContainer = forwardRef<
   147→  DashboardPanelContainerRef,
   148→  DashboardPanelContainerProps
   149→>(
   150→  (
   151→    {
   152→      dashboard,
   153→      dashboardId,
   154→      initialTimeSpan,
   155→      initialFilterExpression,
   156→      initialLoading,
   157→      onChartSelection,
   158→      showSectionEditControls = false,
   159→      onSectionRename,
   160→      onSectionDelete,
   161→      onSectionCollapseChange,
   162→      children,
   163→    },
   164→    ref
   165→  ) => {
   166→    // Track individual panel collapse states (keyed by global panel index)
   167→    const [panelCollapseStates, setPanelCollapseStates] = useState<Map<number, boolean>>(new Map());
   168→    // Track section collapse states (keyed by section index) - local state, not persisted
   169→    const [sectionCollapseStates, setSectionCollapseStates] = useState<Map<number, boolean>>(new Map());
   170→    const subComponentRefs = useRef<(DashboardVisualizationComponent | null)[]>([]);
   171→
   172→    // Track registered refreshable children
   173→    const registeredChildrenRef = useRef<Set<RefreshableChild>>(new Set());
   174→
   175→    // Memoize the charts array from the dashboard
   176→    const panels = useMemo(() => dashboard.charts, [dashboard]);
   177→
   178→    // Build sections from dashboard panels
   179→    const sections = useMemo<SectionInfo[]>(() => {
   180→      const result: SectionInfo[] = [];
   181→      const ungroupedPanels: PanelDescriptor[] = [];
   182→      let globalPanelIndex = 0;
   183→      let sectionIndex = 0;
   184→
   185→      panels.forEach((item) => {
   186→        if (isDashboardGroup(item)) {
   187→          // This is a group - create a section for it
   188→          result.push({
   189→            group: item,
   190→            sectionIndex,
   191→            panels: item.charts,
   192→            globalPanelStartIndex: globalPanelIndex,
   193→          });
   194→          globalPanelIndex += item.charts.length;
   195→          sectionIndex++;
   196→        } else {
   197→          // Standalone panel - collect into ungrouped
   198→          ungroupedPanels.push(item);
   199→        }
   200→      });
