   662→/**
   663→ * Check if an item is a DashboardGroup
   664→ */
   665→function isDashboardGroup(item: PanelDescriptor | DashboardGroup): item is DashboardGroup {
   666→  return "charts" in item && Array.isArray((item as DashboardGroup).charts);
   667→}
   668→
   669→/**
   670→ * Flatten panels from dashboard config (handles groups)
   671→ */
   672→function flattenPanels(
   673→  panels: (PanelDescriptor | DashboardGroup)[]
   674→): PanelDescriptor[] {
   675→  const result: PanelDescriptor[] = [];
   676→  for (const item of panels) {
   677→    if (isDashboardGroup(item)) {
   678→      result.push(...item.charts);
   679→    } else {
   680→      result.push(item);
   681→    }
   682→  }
   683→  return result;
   684→}
