   686→/**
   687→ * Add a panel to the first section (DashboardGroup).
   688→ * If no section exists, creates a default one.
   689→ */
   690→function addPanelToFirstSection(
   691→  panels: (PanelDescriptor | DashboardGroup)[],
   692→  newPanel: PanelDescriptor
   693→): (PanelDescriptor | DashboardGroup)[] {
   694→  const updatedPanels = [...panels];
   695→
   696→  // Find the first DashboardGroup
   697→  const firstGroupIndex = updatedPanels.findIndex(isDashboardGroup);
   698→
   699→  if (firstGroupIndex >= 0) {
   700→    // Add to existing first group
   701→    const group = updatedPanels[firstGroupIndex] as DashboardGroup;
   702→    updatedPanels[firstGroupIndex] = {
   703→      ...group,
   704→      charts: [...group.charts, newPanel],
   705→    };
   706→  } else {
   707→    // No groups exist - create a default section with this panel
   708→    const defaultSection: DashboardGroup = {
   709→      title: "Default",
   710→      charts: [newPanel],
   711→      collapsed: false,
   712→    };
   713→    updatedPanels.push(defaultSection);
   714→  }
   715→
   716→  return updatedPanels;
   717→}
   718→
   719→/**
   720→ * Update a panel at a flat index (accounting for sections)
   721→ */
   722→function updatePanelAtFlatIndex(
   723→  panels: (PanelDescriptor | DashboardGroup)[],
   724→  flatIndex: number,
   725→  updatedPanel: PanelDescriptor
   726→): (PanelDescriptor | DashboardGroup)[] {
   727→  const result: (PanelDescriptor | DashboardGroup)[] = [];
   728→  let currentFlatIndex = 0;
   729→
   730→  for (const item of panels) {
   731→    if (isDashboardGroup(item)) {
   732→      const groupCharts = [...item.charts];
   733→      let foundInGroup = false;
   734→
   735→      for (let i = 0; i < groupCharts.length; i++) {
   736→        if (currentFlatIndex === flatIndex) {
   737→          groupCharts[i] = updatedPanel;
   738→          foundInGroup = true;
   739→        }
   740→        currentFlatIndex++;
   741→      }
   742→
   743→      result.push(foundInGroup ? { ...item, charts: groupCharts } : item);
   744→    } else {
   745→      if (currentFlatIndex === flatIndex) {
   746→        result.push(updatedPanel);
   747→      } else {
   748→        result.push(item);
   749→      }
   750→      currentFlatIndex++;
   751→    }
   752→  }
   753→
   754→  return result;
   755→}
   756→
   757→/**
   758→ * Delete a panel at a flat index (accounting for sections)
   759→ */
   760→function deletePanelAtFlatIndex(
   761→  panels: (PanelDescriptor | DashboardGroup)[],
   762→  flatIndex: number
   763→): (PanelDescriptor | DashboardGroup)[] {
   764→  const result: (PanelDescriptor | DashboardGroup)[] = [];
   765→  let currentFlatIndex = 0;
   766→
   767→  for (const item of panels) {
   768→    if (isDashboardGroup(item)) {
   769→      const groupCharts: PanelDescriptor[] = [];
   770→
   771→      for (const chart of item.charts) {
   772→        if (currentFlatIndex !== flatIndex) {
   773→          groupCharts.push(chart);
   774→        }
   775→        currentFlatIndex++;
   776→      }
   777→
   778→      // Keep the group even if empty (user can delete section explicitly)
   779→      result.push({ ...item, charts: groupCharts });
   780→    } else {
   781→      if (currentFlatIndex !== flatIndex) {
   782→        result.push(item);
   783→      }
   784→      currentFlatIndex++;
   785→    }
   786→  }
   787→
   788→  return result;
   789→}
