   250→    // Track pending collapse change to notify parent after state update
   251→    const pendingCollapseChangeRef = useRef<{ sectionIndex: number; collapsed: boolean } | null>(null);
   252→
   253→    // Toggle section collapse - uses local state, optionally notifies parent
   254→    const handleSectionToggle = useCallback((sectionIndex: number) => {
