   387→                <DashboardSection
   388→                  key={`section-${section.sectionIndex}`}
   389→                  dashboardId={effectiveDashboardId}
   390→                  sectionIndex={section.sectionIndex}
   391→                  group={section.group}
   392→                  panels={section.panels}
   393→                  isCollapsed={isCollapsed}
   394→                  onToggleCollapse={() => handleSectionToggle(section.sectionIndex)}
