   122→/**
   123→ * Dashboard section component containing a header and a grid of panels.
   124→ * Each section has its own ResponsiveGridLayout for independent drag/resize.
   125→ */
   126→export function DashboardSection({
   127→  dashboardId,
   128→  sectionIndex,
   129→  group,
   130→  panels,
   131→  isCollapsed,
   132→  onToggleCollapse,
   133→  onSubComponentUpdated,
   134→  globalPanelStartIndex,
   135→  initialTimeSpan,
   136→  initialFilterExpression,
   137→  initialLoading,
   138→  panelCollapseStates,
   139→  onPanelCollapsedChange,
   140→  onChartSelection,
   141→  showEditControls = false,
   142→  onRename,
   143→  onDelete,
   144→}: DashboardSectionProps) {
   145→  const { width, mounted, containerRef } = useContainerWidth();
   146→  const saveTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
   147→
   148→  // Generate default layouts
   149→  const defaultLayouts = useMemo(
   150→    () => generateLayoutsFromPanels(panels),
   151→    [panels]
   152→  );
   153→
   154→  // Load saved layouts or use defaults
   155→  const [layouts, setLayouts] = useState<ResponsiveLayouts>(() => {
   156→    const saved = loadSectionLayout(dashboardId, sectionIndex);
   157→    return saved ?? defaultLayouts;
   158→  });
   159→
   160→  // Update layouts when panels change
   161→  useEffect(() => {
   162→    const saved = loadSectionLayout(dashboardId, sectionIndex);
   163→    setLayouts(saved ?? defaultLayouts);
   164→  }, [dashboardId, sectionIndex, defaultLayouts]);
   165→
   166→  // Handle layout change with debounced save
   167→  const onLayoutChange = useCallback(
   168→    (_currentLayout: Layout, allLayouts: ResponsiveLayouts) => {
   169→      setLayouts(allLayouts);
   170→
   171→      // Debounced save
   172→      if (saveTimeoutRef.current) {
   173→        clearTimeout(saveTimeoutRef.current);
   174→      }
   175→      saveTimeoutRef.current = setTimeout(() => {
   176→        saveSectionLayout(dashboardId, sectionIndex, allLayouts);
   177→      }, 500);
   178→    },
   179→    [dashboardId, sectionIndex]
   180→  );
   181→
   182→  // Cleanup timeout on unmount
   183→  useEffect(() => {
   184→    return () => {
   185→      if (saveTimeoutRef.current) {
   186→        clearTimeout(saveTimeoutRef.current);
   187→      }
   188→    };
   189→  }, []);
   190→
   191→  // Breakpoint configuration
   192→  const breakpoints = { lg: 1024, md: 768, sm: 0 };
   193→  const cols = { lg: 24, md: 6, sm: 1 };
   194→
   195→  const sectionTitle = group?.title ?? "Ungrouped";
   196→
   197→  // Don't render header for ungrouped section if there's only ungrouped panels
   198→  const showHeader = group !== null;
   199→
   200→  return (
   201→    <div className="w-full">
   202→      {showHeader && (
   203→        <SectionHeader
   204→          title={sectionTitle}
   205→          isCollapsed={isCollapsed}
   206→          onToggleCollapse={onToggleCollapse}
   207→          showEditControls={showEditControls}
   208→          onRename={onRename}
   209→          onDelete={onDelete}
   210→        />
   211→      )}
   212→
   213→      {!isCollapsed && panels.length > 0 && (
   214→        <div ref={containerRef} className="w-full">
   215→          {mounted && width > 0 && (
   216→            <ResponsiveGridLayout
   217→              className="layout"
   218→              width={width}
   219→              layouts={layouts}
   220→              breakpoints={breakpoints}
   221→              cols={cols}
   222→              rowHeight={36}
   223→              margin={[8, 8]}
   224→              containerPadding={[0, 0]}
   225→              onLayoutChange={onLayoutChange}
   226→              dragConfig={{ enabled: true, bounded: false, handle: ".dashboard-drag-handle", threshold: 3 }}
   227→              compactor={verticalCompactor}
   228→            >
   229→              {panels.map((panel, localIndex) => {
   230→                const globalIndex = globalPanelStartIndex + localIndex;
   231→                const isPanelCollapsed = panelCollapseStates.get(globalIndex) ?? panel.collapsed ?? false;
   232→
   233→                return (
   234→                  <div key={`panel-${localIndex}`} className="h-full">
   235→                    <div className={cn("w-full h-full", isPanelCollapsed && "h-auto")}>
   236→                      <DashboardVisualizationPanel
   237→                        descriptor={panel}
   238→                        initialTimeSpan={initialTimeSpan}
   239→                        initialFilterExpression={initialFilterExpression}
   240→                        initialLoading={initialLoading}
   241→                        ref={(el) => onSubComponentUpdated(el, globalIndex)}
   242→                        onCollapsedChange={(collapsed) => onPanelCollapsedChange(globalIndex, collapsed)}
   243→                        onChartSelection={onChartSelection}
   244→                      />
   245→                    </div>
   246→                  </div>
   247→                );
   248→              })}
   249→            </ResponsiveGridLayout>
   250→          )}
   251→        </div>
   252→      )}
   253→
   254→      {!isCollapsed && panels.length === 0 && showEditControls && (
   255→        <div className="px-4 py-8 text-center text-sm text-muted-foreground border-b">
   256→          No panels in this section. Add panels to get started.
   257→        </div>
   258→      )}
   259→    </div>
   260→  );
   261→}
