     3→export const STORAGE_KEY_PREFIX = 'dashboard-layout:';
     4→const CURRENT_VERSION = 1;
     5→
     6→export interface SavedLayout {
     7→  version: number;
     8→  dashboardId: string;
     9→  layouts: ResponsiveLayouts;
    10→  updatedAt: string;
    11→}
    12→
    13→/**
    14→ * Generate storage key for a section-specific layout
    15→ * Format: dashboard-layout:{dashboardId}-section-{sectionIndex}
    16→ */
    17→function getSectionKey(dashboardId: string, sectionIndex: number): string {
    18→  return `${STORAGE_KEY_PREFIX}${dashboardId}-section-${sectionIndex}`;
    19→}
    20→
    21→/**
    22→ * Save layout for a specific section of a dashboard
    23→ */
    24→export function saveSectionLayout(
    25→  dashboardId: string,
    26→  sectionIndex: number,
    27→  layouts: ResponsiveLayouts
    28→): void {
    29→  const data: SavedLayout = {
    30→    version: CURRENT_VERSION,
    31→    dashboardId: `${dashboardId}-section-${sectionIndex}`,
    32→    layouts,
    33→    updatedAt: new Date().toISOString(),
    34→  };
    35→  localStorage.setItem(getSectionKey(dashboardId, sectionIndex), JSON.stringify(data));
    36→}
    37→
    38→/**
    39→ * Load layout for a specific section of a dashboard
    40→ */
    41→export function loadSectionLayout(
    42→  dashboardId: string,
    43→  sectionIndex: number
    44→): ResponsiveLayouts | null {
    45→  try {
    46→    const stored = localStorage.getItem(getSectionKey(dashboardId, sectionIndex));
    47→    if (!stored) return null;
    48→
    49→    const data: SavedLayout = JSON.parse(stored);
    50→    if (data.version !== CURRENT_VERSION) return null;
    51→
    52→    return data.layouts;
    53→  } catch {
    54→    return null;
    55→  }
    56→}
    57→
    58→/**
    59→ * Clear layout for a specific section of a dashboard
    60→ */
    61→export function clearSectionLayout(dashboardId: string, sectionIndex: number): void {
    62→  localStorage.removeItem(getSectionKey(dashboardId, sectionIndex));
    63→}
    64→
    65→/**
    66→ * Clear all section layouts for a dashboard (used for reset)
    67→ * Scans localStorage for all keys matching the dashboard prefix
    68→ */
    69→export function clearAllSectionLayouts(dashboardId: string): void {
    70→  const prefix = `${STORAGE_KEY_PREFIX}${dashboardId}-section-`;
    71→  const keysToRemove: string[] = [];
    72→
    73→  for (let i = 0; i < localStorage.length; i++) {
    74→    const key = localStorage.key(i);
    75→    if (key && key.startsWith(prefix)) {
    76→      keysToRemove.push(key);
    77→    }
    78→  }
    79→
    80→  keysToRemove.forEach(key => localStorage.removeItem(key));
    81→}
