    83→// Legacy functions for backwards compatibility (single-grid dashboards)
    84→export function saveDashboardLayout(
    85→  dashboardId: string,
    86→  layouts: ResponsiveLayouts
    87→): void {
    88→  const data: SavedLayout = {
    89→    version: CURRENT_VERSION,
    90→    dashboardId,
    91→    layouts,
    92→    updatedAt: new Date().toISOString(),
    93→  };
    94→  localStorage.setItem(`${STORAGE_KEY_PREFIX}${dashboardId}`, JSON.stringify(data));
    95→}
    96→
    97→export function loadDashboardLayout(
    98→  dashboardId: string
    99→): ResponsiveLayouts | null {
   100→  try {
   101→    const stored = localStorage.getItem(`${STORAGE_KEY_PREFIX}${dashboardId}`);
   102→    if (!stored) return null;
   103→
   104→    const data: SavedLayout = JSON.parse(stored);
   105→    if (data.version !== CURRENT_VERSION) return null;
   106→
   107→    return data.layouts;
   108→  } catch {
   109→    return null;
   110→  }
   111→}
