   299→ * @param reducer - The reducer type to apply
   300→ * @returns The reduced value, or 0 if no valid data
   301→ */
   302→export function applyReducer(data: (number | null | undefined)[], reducer: Reducer): number {
   303→  // Filter out null and undefined values
   304→  const values = data.filter((v): v is number => v !== null && v !== undefined);
   305→
   306→  if (values.length === 0) {
   307→    return 0;
   308→  }
   309→
   310→  switch (reducer) {
   311→    case "min":
   312→      return Math.min(...values);
   313→    case "max":
   314→      return Math.max(...values);
   315→    case "sum":
   316→      return values.reduce((acc, val) => acc + val, 0);
   317→    case "count":
   318→      return values.length;
   319→    case "first":
   320→      return values[0];
   321→    case "last":
   322→      return values[values.length - 1];
   323→    case "avg":
   324→      return values.reduce((acc, val) => acc + val, 0) / values.length;
   325→  }
   326→}
